     1|import AsyncStorage from '@react-native-async-storage/async-storage';
     2|import type { ChatMessage } from '@/types';
     3|
     4|/**
     5| * Conversation persistence for the in-app Chat. Messages are saved per chat
     6| * `source` so a conversation resumes after the app restarts, while staying
     7| * bounded so old turns never bloat storage. Attachments still uploading at
     8| * save time are normalized to a stable state so a resumed conversation never
     9| * shows a permanent "uploading" spinner.
    10| */
    11|
    12|const KEY_PREFIX = '@ivx_chat_history_v1:';
    13|const MAX_PERSISTED_MESSAGES = 80;
    14|
    15|function storageKey(source: string): string {
    16|  return `${KEY_PREFIX}${source}`;
    17|}
    18|
    19|function normalizeForPersistence(messages: ChatMessage[]): ChatMessage[] {
    20|  return messages.slice(-MAX_PERSISTED_MESSAGES).map((message) => {
    21|    if (!message.attachments || message.attachments.length === 0) {
    22|      return message;
    23|    }
    24|
    25|    return {
    26|      ...message,
    27|      attachments: message.attachments.map((attachment) => {
    28|        if (attachment.status === 'uploading') {
    29|          return attachment.url
    30|            ? { ...attachment, status: 'ready' as const }
    31|            : { ...attachment, status: 'failed' as const, error: attachment.error ?? 'Upload was interrupted.' };
    32|        }
    33|        return attachment;
    34|      }),
    35|    };
    36|  });
    37|}
    38|
    39|/** Load a previously saved conversation for a chat source, or null if none. */
    40|export async function loadChatHistory(source: string): Promise<ChatMessage[] | null> {
    41|  try {
    42|    const raw = await AsyncStorage.getItem(storageKey(source));
    43|    if (!raw) {
    44|      return null;
    45|    }
    46|
    47|    const parsed = JSON.parse(raw) as ChatMessage[];
    48|    if (!Array.isArray(parsed) || parsed.length === 0) {
    49|      return null;
    50|    }
    51|
    52|    return parsed.filter((message) => typeof message?.id === 'string' && typeof message?.message === 'string');
    53|  } catch (error) {
    54|    console.log('[ChatPersistence] Load failed:', (error as Error)?.message);
    55|    return null;
    56|  }
    57|}
    58|
    59|/** Persist the current conversation for a chat source (bounded + normalized). */
    60|export async function saveChatHistory(source: string, messages: ChatMessage[]): Promise<void> {
    61|  try {
    62|    if (messages.length === 0) {
    63|      return;
    64|    }
    65|    await AsyncStorage.setItem(storageKey(source), JSON.stringify(normalizeForPersistence(messages)));
    66|  } catch (error) {
    67|    console.log('[ChatPersistence] Save failed:', (error as Error)?.message);
    68|  }
    69|}
    70|
    71|/** Clear the saved conversation for a chat source. */
    72|export async function clearChatHistory(source: string): Promise<void> {
    73|  try {
    74|    await AsyncStorage.removeItem(storageKey(source));
    75|  } catch (error) {
    76|    console.log('[ChatPersistence] Clear failed:', (error as Error)?.message);
    77|  }
