   535|function buildOwnerAIProxyStatusUrl(audit: IVXOwnerAIConfigAudit): string | null {
   536|  const baseUrl = safeTrim(audit.activeBaseUrl).replace(/\/+$/, '');
   537|  return baseUrl ? `${baseUrl}/api/ivx/owner-ai/proxy-status` : null;
